import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db } from '../firebase';
import { collection, getDocs, addDoc, Timestamp } from 'firebase/firestore';

function CreateTeam() {
  const { gameId } = useParams();
  const navigate = useNavigate();

  const [teamData, setTeamData] = useState({
    name: '',
    color: '#386C0B',
    playerCount: 4,
    tactic: 'Strategy 1',
    entranceSong: '',
    players: [],
  });

  const [availablePlayers, setAvailablePlayers] = useState([]);
  const [selectedPlayers, setSelectedPlayers] = useState([]);
  const tactics = ['Strategy 1', 'Strategy 2', 'Strategy 3'];

  useEffect(() => {
    const fetchPlayers = async () => {
      const playersCollection = await getDocs(collection(db, 'players'));
      const playersData = playersCollection.docs.map(doc => ({
        id: doc.id,
        ...doc.data(),
      }));
      setAvailablePlayers(playersData);
    };
    fetchPlayers();
  }, []);

  const handleChange = (e) => {
    setTeamData({ ...teamData, [e.target.name]: e.target.value });
  };

  const handlePlayerSelect = (player) => {
    if (selectedPlayers.length < teamData.playerCount) {
      setSelectedPlayers([...selectedPlayers, player]);
    } else {
      alert(`You can only select ${teamData.playerCount} players.`);
    }
  };

  const handlePlayerRemove = (playerId) => {
    setSelectedPlayers(selectedPlayers.filter(p => p.id !== playerId));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await addDoc(collection(db, 'teams'), {
        ...teamData,
        players: selectedPlayers.map(p => p.id),
        gameId: gameId,
        createdAt: Timestamp.now(),
      });
      alert('Team created successfully!');
      navigate('/set-game');
    } catch (error) {
      console.error('Error creating team:', error);
      alert('Failed to create team.');
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Create Team</h1>
      <form onSubmit={handleSubmit} style={styles.form}>
        <label style={styles.label}>Team Name</label>
        <input
          type="text"
          name="name"
          placeholder="Enter team name"
          value={teamData.name}
          onChange={handleChange}
          required
          style={styles.input}
        />

        <label style={styles.label}>Team Color</label>
        <input
          type="color"
          name="color"
          value={teamData.color}
          onChange={handleChange}
          style={styles.colorInput}
        />

        <label style={styles.label}>Number of Players</label>
        <select
          name="playerCount"
          value={teamData.playerCount}
          onChange={handleChange}
          style={styles.select}
        >
          <option value={4}>4 Players</option>
          <option value={5}>5 Players</option>
          <option value={6}>6 Players</option>
        </select>

        <label style={styles.label}>Select Tactic</label>
        <select
          name="tactic"
          value={teamData.tactic}
          onChange={handleChange}
          style={styles.select}
        >
          {tactics.map((tactic, index) => (
            <option key={index} value={tactic}>{tactic}</option>
          ))}
        </select>

        <label style={styles.label}>Entrance Song (YouTube Link)</label>
        <input
          type="url"
          name="entranceSong"
          placeholder="Paste YouTube link"
          value={teamData.entranceSong}
          onChange={handleChange}
          style={styles.input}
        />

        <h3 style={styles.subTitle}>Select Players</h3>
        <div style={styles.playersList}>
          {availablePlayers.map(player => (
            <div key={player.id} style={styles.playerCard}>
              <p>{player.firstName} {player.lastName}</p>
              <p>Power: {player.powerRating}</p>
              <button type="button" onClick={() => handlePlayerSelect(player)} style={styles.addButton}>
                Add
              </button>
            </div>
          ))}
        </div>

        <h3 style={styles.subTitle}>Selected Players</h3>
        <div style={styles.selectedPlayers}>
          {selectedPlayers.map(player => (
            <div key={player.id} style={styles.playerCard}>
              <p>{player.firstName} {player.lastName}</p>
              <button type="button" onClick={() => handlePlayerRemove(player.id)} style={styles.removeButton}>
                Remove
              </button>
            </div>
          ))}
        </div>

        <button type="submit" style={styles.button}>Create Team</button>
      </form>
    </div>
  );
}

const styles = {
  container: { backgroundColor: '#D6F8D6', padding: '20px', fontFamily: "'Press Start 2P', cursive" },
  title: { fontSize: '24px', color: '#293F14' },
  form: { display: 'flex', flexDirection: 'column', gap: '20px' },
  label: { fontSize: '14px', color: '#293F14' },
  input: { padding: '10px', borderRadius: '8px' },
  select: { padding: '10px', borderRadius: '8px' },
  colorInput: { width: '100%', height: '40px' },
  playersList: { display: 'flex', flexWrap: 'wrap', gap: '10px' },
  selectedPlayers: { display: 'flex', gap: '10px' },
  playerCard: { padding: '10px', border: '1px solid #293F14', borderRadius: '8px' },
  button: { padding: '10px', backgroundColor: '#386C0B', color: '#FFF' },
  addButton: { backgroundColor: '#7FC6A4' },
  removeButton: { backgroundColor: '#FF4D4D' }
};

export default CreateTeam;
